pub fn enable_interrupts() {
    #[cfg(target_arch = "riscv64")]
    unsafe {
        core::arch::asm!("csrs sstatus, {}", in(reg) 1usize << 1);
    }
    #[cfg(target_arch = "loongarch64")]
    {
        loongarch64::enable_interrupts();
    }
}

